import{_ as t,a,b as o,c as d,d as n,e as r}from"./chunks/查询额度成功.BKueuYqe.js";import{_ as p,o as l,c as i,a2 as s}from"./chunks/framework.DnrXFDHb.js";const x=JSON.parse('{"title":"Een Dropbox-kanaal toevoegen","description":"","frontmatter":{},"headers":[],"relativePath":"nl-NL/upload/dropbox.md","filePath":"nl-NL/upload/dropbox.md","lastUpdated":1781962217000}'),c={name:"nl-NL/upload/dropbox.md"};function h(b,e,g,u,k,m){return l(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="een-dropbox-kanaal-toevoegen" tabindex="-1">Een Dropbox-kanaal toevoegen <a class="header-anchor" href="#een-dropbox-kanaal-toevoegen" aria-label="Permalink to &quot;Een Dropbox-kanaal toevoegen&quot;">​</a></h1><h2 id="wat-je-vooraf-nodig-hebt" tabindex="-1">Wat je vooraf nodig hebt <a class="header-anchor" href="#wat-je-vooraf-nodig-hebt" aria-label="Permalink to &quot;Wat je vooraf nodig hebt&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Vereiste</th><th>Waarom je dit nodig hebt</th></tr></thead><tbody><tr><td>Dropbox-account</td><td>Voor aanmelden en autoriseren van de app</td></tr><tr><td>Dropbox-app</td><td>Voor het genereren van <code>App Key</code> en <code>App Secret</code></td></tr><tr><td>Je ImgBed-domein</td><td>Voor de OAuth-redirect-URI</td></tr><tr><td>Beschikbare Dropbox-opslag</td><td>De daadwerkelijke opslaglocatie voor bestanden</td></tr></tbody></table><h2 id="instellen" tabindex="-1">Instellen <a class="header-anchor" href="#instellen" aria-label="Permalink to &quot;Instellen&quot;">​</a></h2><h3 id="stap-1-maak-een-dropbox-app" tabindex="-1">Stap 1: Maak een Dropbox-app <a class="header-anchor" href="#stap-1-maak-een-dropbox-app" aria-label="Permalink to &quot;Stap 1: Maak een Dropbox-app&quot;">​</a></h3><ol><li>Open de Dropbox App Console:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://www.dropbox.com/developers/apps</span></span></code></pre></div><ol start="2"><li>Maak een nieuwe app.</li><li>Kies als toegangstype:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>App folder</span></span></code></pre></div><ol start="4"><li>Geef de app een herkenbare naam, bijvoorbeeld <code>imgbed-app</code>.</li><li>Open na het aanmaken de detailpagina van de app.</li></ol><p>Aanbevolen toegangstype:</p><table tabindex="0"><thead><tr><th>Toegangstype</th><th>Aanbeveling</th></tr></thead><tbody><tr><td><code>App folder</code></td><td>Aanbevolen. Dit past bij de manier waarop ImgBed bestanden opslaat.</td></tr><tr><td><code>Full Dropbox</code></td><td>Niet aanbevolen. ImgBed heeft geen volledige toegang tot je account nodig.</td></tr></tbody></table><p><img src="'+t+'" alt="Dropbox-app maken" loading="lazy"></p><h3 id="stap-2-voeg-de-redirect-uri-toe" tabindex="-1">Stap 2: Voeg de Redirect URI toe <a class="header-anchor" href="#stap-2-voeg-de-redirect-uri-toe" aria-label="Permalink to &quot;Stap 2: Voeg de Redirect URI toe&quot;">​</a></h3><p>Zoek op de detailpagina van de Dropbox-app de OAuth- of Redirect URI-instellingen en voeg toe:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/api/oauth/dropbox/callback</span></span></code></pre></div><p>Gebruik je het beheer via meerdere domeinen, voeg dan elke bijpassende callback-URL toe.</p><p><img src="'+a+'" alt="Redirect URI instellen" loading="lazy"></p><h3 id="stap-3-configureer-apprechten" tabindex="-1">Stap 3: Configureer apprechten <a class="header-anchor" href="#stap-3-configureer-apprechten" aria-label="Permalink to &quot;Stap 3: Configureer apprechten&quot;">​</a></h3><p>Open het tabblad <code>Permissions</code> en schakel minstens deze scopes in:</p><table tabindex="0"><thead><tr><th>Scope</th><th>Verplicht</th><th>Doel</th></tr></thead><tbody><tr><td><code>account_info.read</code></td><td>Verplicht</td><td>Leest account- en quotainformatie</td></tr><tr><td><code>files.metadata.read</code></td><td>Verplicht</td><td>Leest bestands- en mapmetadata voor padcontroles</td></tr><tr><td><code>files.metadata.write</code></td><td>Verplicht</td><td>Maakt mappen aan en schrijft metadata</td></tr><tr><td><code>files.content.write</code></td><td>Verplicht</td><td>Uploadt bestanden. Zonder deze scope krijg je <code>required scope &#39;files.content.write&#39;</code>.</td></tr><tr><td><code>files.content.read</code></td><td>Aanbevolen</td><td>Staat download, preview en tijdelijke bestandslinks toe</td></tr></tbody></table><p>Klik na het selecteren onderaan op <code>Submit</code>.</p><p><img src="'+o+'" alt="Rechten toevoegen" loading="lazy"></p><p>Belangrijk:</p><table tabindex="0"><thead><tr><th>Situatie</th><th>Wat je moet doen</th></tr></thead><tbody><tr><td>Je hebt scopes gewijzigd</td><td>Doorloop de tokenautorisatie opnieuw en haal een nieuw <code>Refresh Token</code> op.</td></tr><tr><td>Je hebt niet opnieuw geautoriseerd</td><td>Het oude token krijgt de nieuwe rechten niet automatisch, waardoor uploads kunnen blijven mislukken.</td></tr></tbody></table><h3 id="stap-4-kopieer-appgegevens" tabindex="-1">Stap 4: Kopieer appgegevens <a class="header-anchor" href="#stap-4-kopieer-appgegevens" aria-label="Permalink to &quot;Stap 4: Kopieer appgegevens&quot;">​</a></h3><p>Bewaar deze twee waarden van de Dropbox-app-pagina:</p><table tabindex="0"><thead><tr><th>Dropbox-veld</th><th>ImgBed-veld</th></tr></thead><tbody><tr><td><code>App key</code></td><td><code>App Key</code></td></tr><tr><td><code>App secret</code></td><td><code>App Secret</code></td></tr></tbody></table><h3 id="stap-5-vul-het-dropbox-kanaal-in" tabindex="-1">Stap 5: Vul het Dropbox-kanaal in <a class="header-anchor" href="#stap-5-vul-het-dropbox-kanaal-in" aria-label="Permalink to &quot;Stap 5: Vul het Dropbox-kanaal in&quot;">​</a></h3><p>Kies in Uploadinstellingen <code>Dropbox</code> en vul in:</p><table tabindex="0"><thead><tr><th>ImgBed-veld</th><th>Wat je invult</th></tr></thead><tbody><tr><td>Kanaalnaam</td><td>Een herkenbare naam, bijvoorbeeld <code>Main Dropbox</code></td></tr><tr><td>App Key</td><td>De Dropbox <code>App key</code></td></tr><tr><td>App Secret</td><td>De Dropbox <code>App secret</code></td></tr><tr><td>Refresh Token</td><td>Laat voorlopig leeg</td></tr><tr><td>Hoofdmap</td><td>Optioneel. Standaard <code>imgbed</code>.</td></tr><tr><td>Notitie</td><td>Optioneel</td></tr></tbody></table><p><img src="'+d+'" alt="Token ophalen" loading="lazy"></p><h3 id="stap-6-haal-het-refresh-token-op" tabindex="-1">Stap 6: Haal het Refresh Token op <a class="header-anchor" href="#stap-6-haal-het-refresh-token-op" aria-label="Permalink to &quot;Stap 6: Haal het Refresh Token op&quot;">​</a></h3><ol><li>Klik in ImgBed op <code>Get Token</code>.</li><li>Meld je aan met het Dropbox-account dat je wilt koppelen.</li><li>Keur de autorisatie goed.</li><li>De callbackpagina toont een <code>Refresh Token</code>.</li><li>Kopieer het.</li><li>Ga terug naar ImgBed en plak het in <code>Refresh Token</code>.</li></ol><p><img src="'+n+'" alt="Token kopiëren" loading="lazy"></p><h2 id="controleren" tabindex="-1">Controleren <a class="header-anchor" href="#controleren" aria-label="Permalink to &quot;Controleren&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Controle</th><th>Verwacht resultaat</th></tr></thead><tbody><tr><td>Kanaalkaart</td><td>Het Dropbox-kanaal verschijnt na opslaan.</td></tr><tr><td>Kanaalschakelaar</td><td>Het kanaal kan worden ingeschakeld.</td></tr><tr><td>Token opgeslagen</td><td>De detailpagina toont dat het <code>Refresh Token</code> is opgeslagen.</td></tr><tr><td>Testupload</td><td>Een testafbeelding verschijnt in de app-map van Dropbox.</td></tr></tbody></table><p>Als quotalimieten actief zijn, klik dan op quota opvragen. Na een geslaagde opvraag toont de kanaalkaart gebruikte ruimte, totale ruimte en laatste update.</p><p><img src="'+r+`" alt="Quota-opvraag gelukt" loading="lazy"></p><h2 id="problemen-oplossen" tabindex="-1">Problemen oplossen <a class="header-anchor" href="#problemen-oplossen" aria-label="Permalink to &quot;Problemen oplossen&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Probleem</th><th>Oplossing</th></tr></thead><tbody><tr><td>ImgBed meldt dat de configuratie onvolledig is</td><td>Controleer of <code>App Key</code>, <code>App Secret</code> en <code>Refresh Token</code> allemaal zijn ingevuld.</td></tr><tr><td>Autorisatie lukt, maar er verschijnt geen <code>Refresh Token</code></td><td>Klik opnieuw op <code>Get Token</code> en controleer of de offline autorisatiestroom wordt gebruikt.</td></tr><tr><td>Upload mislukt met <code>required scope &#39;files.content.write&#39;</code></td><td>Schakel <code>files.content.write</code> in, klik op <code>Submit</code> en haal daarna een nieuw <code>Refresh Token</code> op.</td></tr><tr><td>Callback mislukt</td><td>Controleer of de redirect URI <code>https://your-domain.com/api/oauth/dropbox/callback</code> is.</td></tr><tr><td>Bestanden worden niet gevonden</td><td>Controleer of de Dropbox-app in <code>App folder</code>-modus is gemaakt.</td></tr></tbody></table><h2 id="snelle-flow" tabindex="-1">Snelle flow <a class="header-anchor" href="#snelle-flow" aria-label="Permalink to &quot;Snelle flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Open Dropbox App Console</span></span>
<span class="line"><span>-&gt; Maak een app</span></span>
<span class="line"><span>-&gt; Kies App folder access</span></span>
<span class="line"><span>-&gt; Voeg https://your-domain.com/api/oauth/dropbox/callback toe</span></span>
<span class="line"><span>-&gt; Schakel account_info.read / files.metadata.read / files.metadata.write / files.content.write in</span></span>
<span class="line"><span>-&gt; Schakel eventueel files.content.read in</span></span>
<span class="line"><span>-&gt; Klik Submit</span></span>
<span class="line"><span>-&gt; Kopieer App Key en App Secret</span></span>
<span class="line"><span>-&gt; Vul ze in ImgBed in</span></span>
<span class="line"><span>-&gt; Klik Get Token</span></span>
<span class="line"><span>-&gt; Kopieer het Refresh Token van de callbackpagina</span></span>
<span class="line"><span>-&gt; Plak het terug in ImgBed en sla op</span></span></code></pre></div><h2 id="referenties" tabindex="-1">Referenties <a class="header-anchor" href="#referenties" aria-label="Permalink to &quot;Referenties&quot;">​</a></h2><ol><li>Dropbox App Console: <a href="https://www.dropbox.com/developers/apps" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/apps</a></li><li>Dropbox OAuth Guide: <a href="https://developers.dropbox.com/oauth-guide" target="_blank" rel="noreferrer">https://developers.dropbox.com/oauth-guide</a></li><li>Dropbox Developer Guide: <a href="https://www.dropbox.com/developers/reference/developer-guide" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/reference/developer-guide</a></li></ol>`,45)])])}const w=p(c,[["render",h]]);export{x as __pageData,w as default};
